B.an5=new A.hc("Son g\xfcncelleme: 18 Mart 2026",null)
B.anz=new A.hA("Hizmet Tan\u0131m\u0131",null)
B.amZ=new A.hc("Koala, yapay zeka destekli bir mekan analiz uygulamas\u0131d\u0131r. Kullan\u0131c\u0131lar soru foto\u011fraf\u0131 \xe7ekerek ad\u0131m ad\u0131m \xe7\xf6z\xfcm alabilir. Uygulama 9 farkl\u0131 bran\u015fta AI destekli \xf6\u011fretim hizmeti sunar.",null)
